// Keeps image array from input, inserts embedding_text inline with images

const pages = items[0].json.pages;
let output = [];

for (const page of pages) {
  let text = `Page ${page.index}\n\n`;
  let markdown = page.markdown;

  // Replace each image markdown with annotation text if available
  markdown = markdown.replace(/!\[(.*?)\]\((.*?)\)/g, (match, alt, src) => {
    const img = page.images.find(i => i.id === src || i.fileName === src);
    if (img && img.image_annotation) {
      const ann = JSON.parse(img.image_annotation);
      return (
        '{' +
        `Image: [${img.id}]\n` +
        `Type: ${ann.image_type}\n` +
        `Short: ${ann.short_description}\n` +
        `Summary: ${ann.summary}\n` +
        '}'
      );
    }
    return ""; // if no annotation, strip it
  });

  text += markdown.trim();

  output.push({
    json: {
      page_index: page.index,
      embedding_text: text,
      images: page.images   // ✅ keep original images array
    }
  });
}

return output;

// 0. Get document data
let raw = $input.first().json['Document data'];   // raw is an array of pages
let source = $input.first().json['Document name'];
let source_id = $('Insert Document Metadata').first().json.id;

// Helper: return character length of an object's content
function getObjLength(obj) {
  return (obj.content || '').length;
}

function getObjLengthofTextOnly(obj) {
  if (obj.type === 'image_ocr') return 0;
  return (obj.content || '').length;
}

// Split oversized items by char length
function splitOversizedItems(arr, chunkSize) {
  const result = [];
  for (const item of arr) {
    const content = item.content || '';
    if (content.length <= chunkSize) {
      result.push(item);
    } else {
      for (let start = 0; start < content.length; start += chunkSize) {
        const part = content.slice(start, start + chunkSize);
        result.push({ ...item, content: part });
      }
    }
  }
  return result;
}

// Chunking function (per page)
function chunkByCharLength(arr, source, pageNum, chunkSize = 1000) {
  const flat = splitOversizedItems(arr, chunkSize);
  const response = [];
  let idx = 0;
  let charPos = 0;

  while (idx < flat.length) {
    const a = [];
    let sum = 0;
    const from = charPos;

    while (idx < flat.length && sum < chunkSize) {
      const item = flat[idx];
      const len = getObjLength(item);
      const text_len = getObjLengthofTextOnly(item);
      a.push(item);
      sum += len;
      charPos += text_len;
      idx++;
    }

    const to = charPos;
    const metadata = {
      source: source,
      source_metadata_id: source_id,
      loc: { 
        page: pageNum,       // ✅ add page number here
        Characters: { from, to } 
      }
    };

    response.push({
      content: JSON.stringify({
        pageContent: a,
        metadata
      })
    });
  }

  return response;
}

// 1. Run chunking page by page
let chunks = [];
raw.forEach((pageText, pageIndex) => {
  let arr = [{ type: "text", content: pageText }];
  let pageChunks = chunkByCharLength(arr, source, pageIndex + 1, 500); // pageIndex+1 for human-readable page no.
  chunks.push(...pageChunks);
});

// 2. Return in n8n format
return chunks.map(c => ({ json: c }));

const items = $input.all();

const outputItems = items.map(item => {
  const data = item.json;

  // Use existing LinkingUrl if available
  if (data.LinkingUrl) {
    return {
      json: {
        ...data,
        fileUrl: data.LinkingUrl
      }
    };
  }

  // Construct versioned URL
  let fileUrl = '';

  if (data.ServerRelativeUrl && data.UniqueId) {
    // Base URL with server relative path
    fileUrl = 'https://nosta.sharepoint.com' + data.ServerRelativeUrl;

    // Use UniqueId for version parameter (remove hyphens)
    const versionId = data.UniqueId.replace(/-/g, '');
    fileUrl += `?d=w${versionId}`;
  }

  return {
    json: {
      ...data,
      fileUrl: fileUrl
    }
  };
});

return outputItems;

